/**
 * SPIKE ASSET — a hand-processed "vellumized" avatar.
 *
 * This is the output a real pixels→creature pipeline *would* emit for a
 * user-uploaded image, hardcoded here so the spike can render the creature look
 * without building the pipeline. Source image: a cowboy-hatted saguaro ("Pax").
 *
 * The offline pipeline steps this bakes in (see the PR description for the
 * `rembg` + numpy script that produced them):
 *   1. Subject segmentation → the alpha-matted cutout below (WebP data URI), so
 *      the body can grow to fill the screen without dragging the desert scene.
 *   2. Dominant-color extraction → `fillHex`. NOTE: golden-hour light makes the
 *      honest dominant of this image an *amber*, not "cactus green" — k-means
 *      finds no green cluster at all. A real pipeline needs a semantic-color
 *      decision here (literal-dominant vs. subject-identity green); the amber
 *      below is the literal-dominant choice, which happens to match the mood.
 *   3. Face-center placement under the hat brim → `faceCenter`, where the
 *      grafted eyes sit.
 *
 * The eyes are grafted from the *built* library ("goofy"): a photo with no eyes
 * of its own borrows the character system's aliveness. This is the crux of
 * "vellumize" — the four assets below (sprite, color, eyes, face-center) are
 * exactly what every capable voice-room surface reads.
 */

import { BUNDLED_COMPONENTS } from "@/utils/avatar-bundled-components";
import { pathBBox, unionBBox } from "@/utils/eye-bbox";

import type { VoiceRoomEyeArt } from "./voice-room-eyes";

export interface VellumizedCreature {
  /** Alpha-matted subject cutout, segmented from its original background. */
  spriteUrl: string;
  /** Sprite aspect ratio (height / width) — cover-size it without awaiting load. */
  spriteAspect: number;
  /** Dominant color that fills the room behind the sprite. */
  fillHex: string;
  /** Grafted eye art (borrowed from the built library) + its union bbox. */
  eyeArt: VoiceRoomEyeArt;
  /** Where the eyes sit on the sprite, normalized (0..1) to the sprite box. */
  faceCenter: { x: number; y: number };
}

// Graft the built "goofy" eyes — big and friendly, a good fit for a cowboy
// cactus. Framed by the union bbox of their paths, exactly as
// `resolveVoiceRoomLook` frames a character's own eyes.
const GOOFY = BUNDLED_COMPONENTS.eyeStyles.find((e) => e.id === "goofy");
const EYE_ART: VoiceRoomEyeArt = {
  paths: GOOFY?.paths ?? [],
  bbox: unionBBox((GOOFY?.paths ?? []).map((p) => pathBBox(p.svgPath))),
};

// The segmented cutout (WebP w/ alpha), inlined so the story is self-contained.
const PAX_SPRITE = "data:image/webp;base64,";

export const PAX_CREATURE: VellumizedCreature = {
  spriteUrl: PAX_SPRITE,
  // 560×807 sprite → 1.4415. Portrait, so it fills the room vertically.
  spriteAspect: 1.4415,
  // Literal-dominant amber (golden-hour desert). See the color note above.
  fillHex: "#B0762F",
  eyeArt: EYE_ART,
  // Under the hat brim, on the trunk — from the subject-relative face detection.
  faceCenter: { x: 0.492, y: 0.35 },
};
